31	                                                   cudaStream_t stream);
32	
33	template <uint32_t CTA_TILE_Q, uint32_t HEAD_DIM_QK, uint32_t HEAD_DIM_VO,
34	          PosEncodingMode POS_ENCODING_MODE, bool USE_FP16_QK_REDUCTION, MaskMode MASK_MODE,
35	          typename AttentionVariant, typename Params>
36	cudaError_t BatchPrefillWithRaggedKVCacheDispatched(Params params, typename Params::DTypeO* tmp_v,
37	                                                    float* tmp_s, bool enable_pdl,
38	                                                    cudaStream_t stream);
