44	using tvm::ffi::Array;
45	using tvm::ffi::Optional;
46	
47	Array<int64_t> BatchPrefillWithKVCachePlan(
48	    TensorView float_workspace_buffer, TensorView int_workspace_buffer,
49	    TensorView page_locked_int_workspace_buffer, TensorView qo_indptr, TensorView kv_indptr,
50	    TensorView kv_len_arr, int64_t total_num_rows, int64_t batch_size, int64_t num_qo_heads,
51	    int64_t num_kv_heads, int64_t page_size, bool enable_cuda_graph, int64_t head_dim_qk,
52	    int64_t head_dim_vo, bool causal, int64_t window_left, int64_t fixed_split_size,
53	    bool disable_split_kv, int64_t num_colocated_ctas = 0) {
54	  size_t float_workspace_size_in_bytes =
55	      float_workspace_buffer.size(0) * get_element_size(float_workspace_buffer);
56	  size_t int_workspace_size_in_bytes =
57	      int_workspace_buffer.size(0) * get_element_size(int_workspace_buffer);
58	
59	  PrefillPlanInfo plan_info;
60	
61	  ffi::CUDADeviceGuard device_guard(float_workspace_buffer.device().device_id);
62	  const cudaStream_t stream = get_stream(float_workspace_buffer.device());
63	  cudaError_t status = PrefillPlan<IdType>(
64	      float_workspace_buffer.data_ptr(), float_workspace_size_in_bytes,
65	      int_workspace_buffer.data_ptr(), page_locked_int_workspace_buffer.data_ptr(),
66	      int_workspace_size_in_bytes, plan_info, static_cast<IdType*>(qo_indptr.data_ptr()),
67	      static_cast<IdType*>(kv_indptr.data_ptr()), total_num_rows, batch_size, num_qo_heads,
68	      num_kv_heads, head_dim_qk, head_dim_vo, page_size, enable_cuda_graph,
69	      /*sizeof_dtype_o=*/2, window_left, fixed_split_size, disable_split_kv, num_colocated_ctas,
70	      stream);
71	
72	  TVM_FFI_ICHECK(status == cudaSuccess)
73	      << "Failed to plan prefill with error: " << cudaGetErrorString(status);
74	
75	  return Array(plan_info.ToVector());
76	}
77	
78	Array<int64_t> BatchPrefillWithKVCacheWorkspaceSize(
79	    TensorView device_buffer, TensorView qo_indptr, TensorView kv_indptr, TensorView kv_len_arr,
80	    int64_t total_num_rows, int64_t batch_size, int64_t num_qo_heads, int64_t num_kv_heads,
81	    int64_t page_size, bool enable_cuda_graph, int64_t head_dim_qk, int64_t head_dim_vo,
82	    bool causal, int64_t window_left, int64_t fixed_split_size, bool disable_split_kv,
83	    int64_t num_colocated_ctas = 0) {
84	  (void)kv_len_arr;
85	  (void)causal;
86	  size_t float_workspace_size_in_bytes = 0;
87	  size_t int_workspace_size_in_bytes = 0;
88	
89	  ffi::CUDADeviceGuard device_guard(device_buffer.device().device_id);
90	  const cudaStream_t stream = get_stream(device_buffer.device());
91	  cudaError_t status = PrefillPlanWorkspaceSize<IdType>(
92	      float_workspace_size_in_bytes, int_workspace_size_in_bytes,
93	      static_cast<IdType*>(qo_indptr.data_ptr()), static_cast<IdType*>(kv_indptr.data_ptr()),
94	      total_num_rows, batch_size, num_qo_heads, num_kv_heads, head_dim_qk, head_dim_vo, page_size,
95	      enable_cuda_graph, /*sizeof_dtype_o=*/2, window_left, fixed_split_size, disable_split_kv,
96	      num_colocated_ctas, stream);
97	
98	  TVM_FFI_ICHECK(status == cudaSuccess)
99	      << "Failed to calculate prefill workspace size with error: " << cudaGetErrorString(status);
100	
101	  std::vector<int64_t> workspace_sizes = {
102	      static_cast<int64_t>(float_workspace_size_in_bytes),
103	      static_cast<int64_t>(int_workspace_size_in_bytes),
104	  };
105	  return Array(workspace_sizes);
106	}
