108	void BatchPrefillWithRaggedKVCacheRun(TensorView float_workspace_buffer,
109	                                      TensorView int_workspace_buffer, Array<int64_t> plan_info_vec,
110	                                      TensorView q, TensorView k, TensorView v,
111	                                      TensorView qo_indptr, TensorView kv_indptr, TensorView o,
112	                                      Optional<TensorView> maybe_lse, int64_t mask_mode_code,
113	                                      int64_t layout, int64_t window_left,
114	                                      bool enable_pdl ADDITIONAL_FUNC_PARAMS) {
115	  PrefillPlanInfo plan_info;
116	  plan_info.FromVector(std::vector<int64_t>(plan_info_vec.begin(), plan_info_vec.end()));
117	  QKVLayout kv_layout = static_cast<QKVLayout>(layout);
118	
119	  int64_t num_qo_heads = q.size(1);
120	  int64_t head_dim_qk = q.size(2);
121	  int64_t num_kv_heads = (kv_layout == QKVLayout::kNHD) ? k.size(1) : k.size(0);
122	  uint32_t q_stride_n = q.stride(0), q_stride_h = q.stride(1), k_stride_n, k_stride_h, v_stride_n,
123	           v_stride_h;
124	  if (kv_layout == QKVLayout::kNHD) {
125	    k_stride_n = k.stride(0);
126	    k_stride_h = k.stride(1);
127	    v_stride_n = v.stride(0);
128	    v_stride_h = v.stride(1);
129	  } else {
130	    k_stride_h = k.stride(0);
131	    k_stride_n = k.stride(1);
132	    v_stride_h = v.stride(0);
133	    v_stride_n = v.stride(1);
134	  }
135	
136	  if (maybe_lse.has_value()) {
137	    const auto& lse = *maybe_lse;
138	    TVM_FFI_ICHECK_EQ(lse.size(0), q.size(0));
139	    TVM_FFI_ICHECK_EQ(lse.size(1), q.size(1));
140	  }
141	
142	  void* float_buffer_ptr = float_workspace_buffer.data_ptr();
143	  void* int_buffer_ptr = int_workspace_buffer.data_ptr();
144	
145	  const MaskMode mask_mode = static_cast<MaskMode>(mask_mode_code);
146	
147	  ffi::CUDADeviceGuard device_guard(float_workspace_buffer.device().device_id);
148	  const cudaStream_t stream = get_stream(float_workspace_buffer.device());
149	
150	  DISPATCH_context(
151	      DTypeQ, DTypeKV, DTypeO, IdType, MASK_MODE, HEAD_DIM_QK, HEAD_DIM_VO, POS_ENCODING_MODE,
152	      USE_SLIDING_WINDOW, USE_LOGITS_SOFT_CAP, USE_FP16_QK_REDUCTION, AttentionVariant,
153	      RaggedParams, PagedParams, [&] {
154	        RaggedParams params;
155	
156	        params.q = static_cast<DTypeQ*>(q.data_ptr());
157	        params.k = static_cast<DTypeKV*>(k.data_ptr());
158	        params.v = static_cast<DTypeKV*>(v.data_ptr());
159	        params.o = static_cast<DTypeO*>(o.data_ptr());
160	        params.lse =
161	            maybe_lse.has_value() ? static_cast<float*>(maybe_lse.value().data_ptr()) : nullptr;
162	        params.q_indptr = static_cast<IdType*>(qo_indptr.data_ptr());
163	        params.kv_indptr = static_cast<IdType*>(kv_indptr.data_ptr());
164	        params.num_qo_heads = num_qo_heads;
165	        params.num_kv_heads = num_kv_heads;
166	        params.group_size = uint_fastdiv(num_qo_heads / num_kv_heads);
167	        params.q_stride_n = q_stride_n;
168	        params.q_stride_h = q_stride_h;
169	        params.k_stride_n = k_stride_n;
170	        params.k_stride_h = k_stride_h;
171	        params.v_stride_n = v_stride_n;
172	        params.v_stride_h = v_stride_h;
173	        params.window_left = window_left;
174	
175	        params.request_indices = nullptr;
176	        params.qo_tile_indices = nullptr;
177	        params.kv_tile_indices = nullptr;
178	        params.merge_indptr = nullptr;
179	        params.o_indptr = nullptr;
180	        params.kv_chunk_size_ptr = nullptr;
181	        params.block_valid_mask = nullptr;
182	        params.total_num_rows = nullptr;
183	        params.max_total_num_rows = 0;
184	        params.padded_batch_size = 0;
185	        params.partition_kv = false;
186	        params.k_sf_stride_page = 0;
187	        params.k_sf_stride_n = 0;
188	        params.k_sf_stride_h = 0;
189	        params.v_sf_stride_page = 0;
190	        params.v_sf_stride_n = 0;
191	        params.v_sf_stride_h = 0;
192	
193	        ADDITIONAL_PARAMS_SETTER
194	
195	        DTypeO* tmp_v = nullptr;
196	        float* tmp_s = nullptr;
197	
198	        params.request_indices =
199	            GetPtrFromBaseOffset<IdType>(int_buffer_ptr, plan_info.request_indices_offset);
200	        params.qo_tile_indices =
201	            GetPtrFromBaseOffset<IdType>(int_buffer_ptr, plan_info.qo_tile_indices_offset);
202	        params.kv_tile_indices =
203	            GetPtrFromBaseOffset<IdType>(int_buffer_ptr, plan_info.kv_tile_indices_offset);
204	        params.o_indptr = GetPtrFromBaseOffset<IdType>(int_buffer_ptr, plan_info.o_indptr_offset);
205	        params.kv_chunk_size_ptr =
206	            GetPtrFromBaseOffset<IdType>(int_buffer_ptr, plan_info.kv_chunk_size_ptr_offset);
207	        if (plan_info.split_kv) {
208	          params.merge_indptr =
209	              GetPtrFromBaseOffset<IdType>(int_buffer_ptr, plan_info.merge_indptr_offset);
210	          tmp_v = GetPtrFromBaseOffset<DTypeO>(float_buffer_ptr, plan_info.v_offset);
211	          tmp_s = GetPtrFromBaseOffset<float>(float_buffer_ptr, plan_info.s_offset);
212	          if (plan_info.enable_cuda_graph) {
213	            params.block_valid_mask =
214	                GetPtrFromBaseOffset<bool>(int_buffer_ptr, plan_info.block_valid_mask_offset);
215	          }
216	        }
217	        params.padded_batch_size = plan_info.padded_batch_size;
218	        params.max_total_num_rows = plan_info.total_num_rows;
219	        if (plan_info.enable_cuda_graph) {
220	          params.total_num_rows =
221	              GetPtrFromBaseOffset<uint32_t>(int_buffer_ptr, plan_info.total_num_rows_offset);
222	        }
223	
224	        cudaError_t status = cudaSuccess;
225	
226	        DISPATCH_CTA_TILE_Q(plan_info.cta_tile_q, CTA_TILE_Q, {
227	          status = flashinfer::BatchPrefillWithRaggedKVCacheDispatched<
228	              CTA_TILE_Q, HEAD_DIM_QK, HEAD_DIM_VO, POS_ENCODING_MODE,
229	              /*use_fp16_qk_reduction=*/USE_FP16_QK_REDUCTION, MASK_MODE, AttentionVariant,
230	              RaggedParams>(params, tmp_v, tmp_s, enable_pdl, stream);
231	        });
232	
233	        TVM_FFI_ICHECK(status == cudaSuccess)
234	            << "BatchPrefillWithRaggedKVCache failed with error " << cudaGetErrorString(status);
235	        return true;
236	      });
237	}
