239	void BatchPrefillWithPagedKVCacheRun(TensorView float_workspace_buffer,
240	                                     TensorView int_workspace_buffer, Array<int64_t> plan_info_vec,
241	                                     TensorView q, TensorView paged_k_cache,
242	                                     TensorView paged_v_cache, TensorView qo_indptr,
243	                                     TensorView paged_kv_indptr, TensorView paged_kv_indices,
244	                                     TensorView paged_kv_last_page_len, TensorView o,
245	                                     Optional<TensorView> maybe_lse, int64_t mask_mode_code,
246	                                     int64_t layout, int64_t window_left,
247	                                     bool enable_pdl ADDITIONAL_FUNC_PARAMS) {
248	  PrefillPlanInfo plan_info;
249	  plan_info.FromVector(std::vector<int64_t>(plan_info_vec.begin(), plan_info_vec.end()));
250	  QKVLayout kv_layout = static_cast<QKVLayout>(layout);
251	  int64_t batch_size = paged_kv_indptr.size(0) - 1;
252	  int64_t num_qo_heads = q.size(1);
253	  int64_t num_kv_heads, page_size;
254	  uint32_t head_dim_qk = q.size(2);
255	  if (kv_layout == QKVLayout::kHND) {
256	    num_kv_heads = paged_k_cache.size(1);
257	    page_size = paged_k_cache.size(2);
258	  } else {
259	    page_size = paged_k_cache.size(1);
260	    num_kv_heads = paged_k_cache.size(2);
261	  }
262	
263	  if (maybe_lse) {
264	    const auto& lse = *maybe_lse;
265	    TVM_FFI_ICHECK_EQ(lse.size(0), q.size(0));
266	    TVM_FFI_ICHECK_EQ(lse.size(1), q.size(1));
267	  }
268	
269	  void* float_buffer_ptr = static_cast<void*>(float_workspace_buffer.data_ptr());
270	  void* int_buffer_ptr = static_cast<void*>(int_workspace_buffer.data_ptr());
271	
272	  const MaskMode mask_mode = static_cast<MaskMode>(mask_mode_code);
273	
274	  // get q_stride_n and q_stride_h
275	  const auto q_stride_n = q.stride(0);
276	  const auto q_stride_h = q.stride(1);
277	
278	  // get kv_cache_strides
279	  const int64_t* kv_cache_strides = paged_k_cache.strides().data();
280	  TVM_FFI_ICHECK_EQ(paged_k_cache.ndim(), paged_v_cache.ndim());
281	  for (int i = 0; i < paged_k_cache.ndim(); ++i) {
282	    TVM_FFI_ICHECK_EQ(paged_k_cache.stride(i), paged_v_cache.stride(i))
283	        << "k/v strides differs at " << i;
284	  }
285	
286	  ffi::CUDADeviceGuard device_guard(float_workspace_buffer.device().device_id);
287	  const cudaStream_t stream = get_stream(float_workspace_buffer.device());
288	
289	  DISPATCH_context(
290	      DTypeQ, DTypeKV, DTypeO, IdType, MASK_MODE, HEAD_DIM_QK, HEAD_DIM_VO, POS_ENCODING_MODE,
291	      USE_SLIDING_WINDOW, USE_LOGITS_SOFT_CAP, USE_FP16_QK_REDUCTION, AttentionVariant,
292	      RaggedParams, PagedParams, [&] {
293	        PagedParams params;
294	
295	        params.q = static_cast<DTypeQ*>(q.data_ptr());
296	        paged_kv_t<DTypeKV, IdType> paged_kv(
297	            num_kv_heads, page_size, HEAD_DIM_VO, batch_size, kv_layout,
298	            static_cast<DTypeKV*>(paged_k_cache.data_ptr()),
299	            static_cast<DTypeKV*>(paged_v_cache.data_ptr()), kv_cache_strides,
300	            static_cast<IdType*>(paged_kv_indices.data_ptr()),
301	            static_cast<IdType*>(paged_kv_indptr.data_ptr()),
302	            static_cast<IdType*>(paged_kv_last_page_len.data_ptr()));
303	        params.paged_kv = paged_kv;
304	        params.q_indptr = static_cast<IdType*>(qo_indptr.data_ptr());
305	        params.o = static_cast<DTypeO*>(o.data_ptr());
306	
307	        params.lse = maybe_lse ? static_cast<float*>(maybe_lse.value().data_ptr()) : nullptr;
308	        params.num_qo_heads = num_qo_heads;
309	        params.group_size = uint_fastdiv(num_qo_heads / paged_kv.num_heads);
310	        params.q_stride_n = q_stride_n;
311	        params.q_stride_h = q_stride_h;
312	        params.window_left = window_left;
313	
314	        params.request_indices = nullptr;
315	        params.qo_tile_indices = nullptr;
316	        params.kv_tile_indices = nullptr;
317	        params.merge_indptr = nullptr;
318	        params.o_indptr = nullptr;
319	        params.kv_chunk_size_ptr = nullptr;
320	        params.block_valid_mask = nullptr;
321	        params.total_num_rows = nullptr;
322	        params.max_total_num_rows = 0;
323	        params.padded_batch_size = 0;
324	        params.partition_kv = false;
325	        params.k_sf_stride_page = 0;
326	        params.k_sf_stride_n = 0;
327	        params.k_sf_stride_h = 0;
328	        params.v_sf_stride_page = 0;
329	        params.v_sf_stride_n = 0;
330	        params.v_sf_stride_h = 0;
331	
332	        ADDITIONAL_PARAMS_SETTER
333	
334	        DTypeO* tmp_v = nullptr;
335	        float* tmp_s = nullptr;
336	
337	        params.request_indices =
338	            GetPtrFromBaseOffset<IdType>(int_buffer_ptr, plan_info.request_indices_offset);
339	        params.qo_tile_indices =
340	            GetPtrFromBaseOffset<IdType>(int_buffer_ptr, plan_info.qo_tile_indices_offset);
341	        params.kv_tile_indices =
342	            GetPtrFromBaseOffset<IdType>(int_buffer_ptr, plan_info.kv_tile_indices_offset);
343	        params.o_indptr = GetPtrFromBaseOffset<IdType>(int_buffer_ptr, plan_info.o_indptr_offset);
344	        params.kv_chunk_size_ptr =
345	            GetPtrFromBaseOffset<IdType>(int_buffer_ptr, plan_info.kv_chunk_size_ptr_offset);
346	        if (plan_info.split_kv) {
347	          params.merge_indptr =
348	              GetPtrFromBaseOffset<IdType>(int_buffer_ptr, plan_info.merge_indptr_offset);
349	          tmp_v = GetPtrFromBaseOffset<DTypeO>(float_buffer_ptr, plan_info.v_offset);
350	          tmp_s = GetPtrFromBaseOffset<float>(float_buffer_ptr, plan_info.s_offset);
351	          if (plan_info.enable_cuda_graph) {
352	            params.block_valid_mask =
353	                GetPtrFromBaseOffset<bool>(int_buffer_ptr, plan_info.block_valid_mask_offset);
354	          }
355	        }
356	        params.padded_batch_size = plan_info.padded_batch_size;
357	        params.max_total_num_rows = plan_info.total_num_rows;
358	        if (plan_info.enable_cuda_graph) {
359	          params.total_num_rows =
360	              GetPtrFromBaseOffset<uint32_t>(int_buffer_ptr, plan_info.total_num_rows_offset);
361	        }
362	
363	        cudaError_t status = cudaSuccess;
364	
365	        DISPATCH_CTA_TILE_Q(plan_info.cta_tile_q, CTA_TILE_Q, {
366	          status = flashinfer::BatchPrefillWithPagedKVCacheDispatched<
367	              CTA_TILE_Q, HEAD_DIM_QK, HEAD_DIM_VO, POS_ENCODING_MODE,
368	              /*use_fp16_qk_reduction=*/USE_FP16_QK_REDUCTION, MASK_MODE, AttentionVariant,
369	              PagedParams>(params, tmp_v, tmp_s, enable_pdl, stream);
370	        });
371	
372	        TVM_FFI_ICHECK(status == cudaSuccess)
373	            << "BatchPrefillWithPagedKVCache failed with error " << cudaGetErrorString(status);
374	        return true;
375	      });
376	}
